async function fetchText(url) {
  try {
    const res = await fetch(url, { cache: 'no-store', credentials: 'include' });
    if (!res.ok) throw new Error('HTTP ' + res.status);
    return res.text();
  } catch (err) {
    console.error('Fetch failed for ' + url + ':', err);
    throw err;
  }
}

